class Zaman:
    def __init__(self, saat, dakika):
        self.saat = saat
        self.dakika = dakika
    def __str__(self):
        return f'{self.saat:02d}:{self.dakika:02d}'
    def __add__(self, diger):
        toplam = self.dakika + diger.dakika
        h = self.saat + diger.saat + toplam // 60
        m = toplam % 60
        return Zaman(h % 24, m)

