SELECT ad, maas
FROM calisanlar
WHERE maas > (SELECT AVG(maas) FROM calisanlar);

SELECT ad, maas,
       ROW_NUMBER() OVER (ORDER BY maas DESC) AS sira
FROM calisanlar;

WITH sirali AS (
    SELECT ad, maas,
           ROW_NUMBER() OVER (ORDER BY maas DESC) AS sira
    FROM calisanlar
)
SELECT ad, maas FROM sirali WHERE sira <= 3;

